    <link rel="stylesheet" :href="`${apiUrl}/20192024/css/style_maps.css`">
    <link rel="stylesheet" :href="`${apiUrl}/20192024/css/styles-slider.css`">

    <v-app-bar app dark elevation="10" color="#9b162e" clipped-left src="@/assets/logos/CINTA.png">
      <!-- <v-app-bar-nav-icon v-if="$store.state.S20192024.drawer_left_map.actived" @click.stop="$store.state.S20192024.drawer_left_map.show=!$store.state.S20192024.drawer_left_map.show"></v-app-bar-nav-icon> -->
      <v-toolbar-title>2019–2024</v-toolbar-title>
      <v-spacer></v-spacer>
      <img src="@/assets/logos/siepi_blanco.png" style=" margin-top: 2px; margin-bottom: 5px; margin-right: 25px; width: 100%; max-width: 200px; height: auto; cursor: pointer;">
    </v-app-bar>

