  </div>

</template>

<script>
import HeaderComp from '@/components/20192024/HeaderComp.vue'
import FooterComp from '@/components/20192024/FooterComp.vue'
import ViewFiles from '@/components/20192024/ViewFilesComp.vue'
import LoaderComp from '@/components/20192024/LoaderComp.vue'
import ImagesCarouselComp from '@/components/20192024/ImagesCarouselComp.vue'

import { mapState, mapActions } from 'vuex'

export default {
  name: 'LegacyLayout',
  components: {
    HeaderComp,
    FooterComp,
    ViewFiles,
    LoaderComp,
    ImagesCarouselComp
  },
  computed: {
    ...mapState('S20192024', [
      'urlParams'
    ]),
    apiUrl () {
      return process.env.VUE_APP_API_URL
    }
  },
  methods: {
    ...mapActions('S20192024', [
      'getParams'
    ])
  },
  beforeDestroy () {
    window.removeEventListener('popstate', this.getParams)
  },
  async created () {
    await this.getParams(null)
    await window.addEventListener('popstate', this.getParams)
  }
}
</script>

