<template>
  <section>
    <v-carousel cycle :height="carouselHeight" reverse-transition="fade-transition" transition="fade-transition" class="grey darken-4">
      <v-carousel-item contain v-for="(item,i) in carousel" :key="i" :src="item.img" @click="expandFile({type: 'open_window', src:item.page})"></v-carousel-item>
    </v-carousel>
    <!-- barra de bavegacion -->
    <div class="text-center">
      <v-sheet class="mx-auto" color="#9b162e">
        <v-btn class="ma-1 card-link" color="white" plain small to="/"> inicio 2024-2030 </v-btn>
        <v-btn class="ma-1 card-link" color="white" plain small to="/2019-2024/" exact> inicio 2019-2024 </v-btn>
        <v-btn class="ma-1 card-link" color="white" plain small to="/2019-2024/materiales-didacticos"> material didácticos </v-btn>
        <v-btn class="ma-1 card-link" color="white" plain small to="/2019-2024/consejos-regionales"> consejos regionales </v-btn>
        <v-btn class="ma-1 card-link" color="white" plain small to="/2019-2024/consejo-estatal"> consejo estatal </v-btn>
        <v-btn class="ma-1 card-link" color="white" plain small to="/2019-2024/documentales"> documentales </v-btn>
        <v-btn class="ma-1 card-link" color="white" plain small to="/2019-2024/libros"> libros </v-btn>
        <v-btn class="ma-1 card-link" color="white" plain small to="/2019-2024/mid"> MID </v-btn>
      </v-sheet>
    </div>
  </section>
</template>

<script>
import { mapActions, mapState } from 'vuex'

export default {
  name: 'HeaderCard',
  data () {
    return {
      carousel: []
    }
  },
  computed: {
    ...mapState('S20192024', [
      'carouselHeight'
    ])
  },
  methods: {
    ...mapActions('S20192024', [
      'setUrl',
      'updateWindowWidth',
      'expandFile',
      'loadData'
    ]),
    handleResize () {
      this.updateWindowWidth()
    }
  },
  destroyed () {
    window.removeEventListener('resize', this.handleResize)
  },
  async created () {
    window.addEventListener('resize', this.handleResize)
    this.handleResize()
    this.carousel = await this.loadData('20192024/json/carousel.json')
  }
}
</script>
